    /**
     * @method
     * @name foxbit#fetchTransactions
     * @description Fetch all transactions (deposits and withdrawals) made from an account.
     * @see https://docs.foxbit.com.br/rest/v3/#tag/Withdrawal/operation/WithdrawalsController_listWithdrawals
     * @see https://docs.foxbit.com.br/rest/v3/#tag/Deposit/operation/DepositsController_listOrders
     * @param {string} [code] unified currency code
     * @param {int} [since] the earliest time in ms to fetch withdrawals for
     * @param {int} [limit] the maximum number of withdrawal structures to retrieve
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} a list of [transaction structures]{@link https://docs.ccxt.com/?id=transaction-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTransactions(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object code = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            Object withdrawals = (this.fetchWithdrawals(code, since, limit, parameters)).join();
            Object deposits = (this.fetchDeposits(code, since, limit, parameters)).join();
            Object allTransactions = this.arrayConcat(withdrawals, deposits);
            Object result = this.sortBy(allTransactions, "timestamp");
            return result;
        });

    }

    /**
     * @method
     * @name foxbit#fetchStatus
     * @description The latest known information on the availability of the exchange API.
     * @see https://status.foxbit.com/
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [status structure]{@link https://docs.ccxt.com/?id=exchange-status-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchStatus(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object response = (this.statusPublicGetStatus(parameters)).join();
            // {
            //     "data": {
            //       "id": 1,
            //       "attributes": {
            //         "status": "NORMAL",
            //         "createdAt": "2023-05-17T18:37:05.934Z",
            //         "updatedAt": "2024-04-17T02:33:50.945Z",
            //         "publishedAt": "2023-05-17T18:37:07.653Z",
            //         "locale": "pt-BR"
            //       }
            //     },
            //     "meta": {
            //     }
            // }
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            Object attributes = this.safeDict(data, "attributes", new java.util.HashMap<String, Object>() {{}});
            Object statusRaw = this.safeString(attributes, "status");
            Object statusMap = new java.util.HashMap<String, Object>() {{
                put( "NORMAL", "ok" );
                put( "UNDER_MAINTENANCE", "maintenance" );
            }};
            return new java.util.HashMap<String, Object>() {{
                put( "status", FoxbitCore.this.safeString(statusMap, statusRaw, statusRaw) );
                put( "updated", FoxbitCore.this.safeString(attributes, "updatedAt") );
                put( "eta", null );
                put( "url", null );
                put( "info", response );
            }};
        });

    }

