    public Object parseOrder(Object order, Object... optionalArgs)
    {
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object symbol = this.safeString(order, "market_symbol");
        if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(market, null)) && Helpers.isTrue(!Helpers.isEqual(symbol, null))))
        {
            market = this.market(symbol);
        }
        if (Helpers.isTrue(!Helpers.isEqual(market, null)))
        {
            symbol = Helpers.GetValue(market, "symbol");
        }
        Object timestamp = this.parseDate(this.safeString(order, "created_at"));
        Object price = this.safeString(order, "price");
        Object filled = this.safeString(order, "quantity_executed");
        Object remaining = this.safeString(order, "quantity");
        // TODO: validate logic of amount here, should this be calculated?
        Object amount = null;
        if (Helpers.isTrue(Helpers.isTrue(!Helpers.isEqual(remaining, null)) && Helpers.isTrue(!Helpers.isEqual(filled, null))))
        {
            amount = Precise.stringAdd(remaining, filled);
        }
        Object cost = this.safeString(order, "funds_received");
        if (!Helpers.isTrue(cost))
        {
            Object priceAverage = this.safeString(order, "price_avg");
            Object priceToCalculate = this.safeString(order, "price", priceAverage);
            cost = Precise.stringMul(priceToCalculate, amount);
        }
        Object side = this.safeStringLower(order, "side");
        Object feeCurrency = this.safeStringUpper(market, "quoteId");
        if (Helpers.isTrue(Helpers.isEqual(side, "buy")))
        {
            feeCurrency = this.safeStringUpper(market, "baseId");
        }
        final Object finalMarket = market;
        final Object finalSide = side;
        final Object finalCost = cost;
        final Object finalAmount = amount;
        final Object finalFilled = filled;
        final Object finalRemaining = remaining;
        final Object finalFeeCurrency = feeCurrency;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "id", FoxbitCore.this.safeString(order, "id") );
            put( "info", order );
            put( "clientOrderId", FoxbitCore.this.safeString(order, "client_order_id") );
            put( "timestamp", timestamp );
            put( "datetime", FoxbitCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", null );
            put( "status", FoxbitCore.this.parseOrderStatus(FoxbitCore.this.safeString(order, "state")) );
            put( "symbol", FoxbitCore.this.safeString(finalMarket, "symbol") );
            put( "type", FoxbitCore.this.safeString(order, "type") );
            put( "timeInForce", FoxbitCore.this.safeString(order, "time_in_force") );
            put( "postOnly", FoxbitCore.this.safeBool(order, "post_only") );
            put( "reduceOnly", null );
            put( "side", finalSide );
            put( "price", FoxbitCore.this.parseNumber(price) );
            put( "triggerPrice", FoxbitCore.this.safeNumber(order, "stop_price") );
            put( "takeProfitPrice", null );
            put( "stopLossPrice", null );
            put( "cost", FoxbitCore.this.parseNumber(finalCost) );
            put( "average", FoxbitCore.this.safeNumber(order, "price_avg") );
            put( "amount", FoxbitCore.this.parseNumber(finalAmount) );
            put( "filled", FoxbitCore.this.parseNumber(finalFilled) );
            put( "remaining", FoxbitCore.this.parseNumber(finalRemaining) );
            put( "trades", null );
            put( "fee", new java.util.HashMap<String, Object>() {{
                put( "currency", finalFeeCurrency );
                put( "cost", FoxbitCore.this.safeNumber(order, "fee_paid") );
            }} );
        }});
    }

